-- tedw_release_summary
VALUES (
'
<span style="background-color: #9D0208; color: white; font-weight: bold; font-size: 18px; padding: 5px; display: inline-block; text-decoration: underline;">Release Summary - 11/04/2024 :</span>
<h4 style="margin-top: 0;">This release includes the following:</h4>
<ol>
    <li>Enhancements - 5
        <ul>
			<li>Added state filings 11/02 release related 17 new columns for Home/Condo.</li>
			<li>Added 2 new columns related to Programmatic and non programmatic discounts for Home/Condo (fortified_roof_program_discount_amt, non_program_discount_amt).</li>
			<li>Added state filings 10/05 release related 3 new columns for Auto (excluded_driver_in, excluded_drivers_for_all_vehicles_in, excluded_driver_for_listed_vehicles).</li>
			<li>Backfilled wildfire protection data using information gathered from manual forms for the Redzone feed. </li>
			<li>Added new column scheduled_item_deleted_in to tcollection_scheduled_item table.</li>
				
		</ul>
    </li>
    <li>Bug tickets - 13
        <ul>
			<li>External Integrations - Hubspot Fixes</li>
				a) Revised logic for Renewal Underwriters to be sent as blank, indicating a pool for brokers with multiple renewal underwriters<br>
				b) Updated logic to resolve missing customers related to insured_type = "entity" in the customer feed<br>
				c) Updated logic to resolve missing quotes related to insured_type = "entity" in the quote feed	
			<li>Data Standardization - Fixed home_cyber_protection_coverage_limit_amt and home_systems_protection_limit_amt for a few Home policies based on its associated indicators. </li>
			<li>Resolved 3 tickets associated with repushing of policies associated with data fixes applied on IVANS.</li>
			<li>Resolved 3 tickets associated with roofCoverageEndorsementRV; roofCoverageEndorsementWH; roofCoverageEndorsementAP; roofExclusionWEnsuingLoss fields by making them null.</li>
			<li>Resolved 1 ticket associated with deleting duplicate cancelled transaction for one policy.</li>
			<li>Resolved 1 ticket associated with updating missing built_yr for a few policies.</li>
			<li>Resolved 1 ticket associated with updating missing rating_territory_cd for a few NC policies.</li>
			<li>Resolved 1 ticket associated with adding notes in Metal for a few policies as per user request.</li>
		</ul>
    </li>
</ol>
'
,'Yes'
,'2024-11-04'
,getdate()
,getdate()
)
;

